// src/ManageOfficers.js
import React from 'react';
import './manageOfficers.css';

const ManageOfficers = () => {
  const officers = [
    { id: 1, name: "John Doe", position: "Manager" },
    { id: 2, name: "Jane Smith", position: "Officer" },
    { id: 3, name: "Alice Johnson", position: "Coordinator" },
    { id: 4, name: "Bob Brown", position: "Officer" },
    { id: 5, name: "Charlie Davis", position: "Assistant" },
    { id: 6, name: "Dana White", position: "Manager" },
    { id: 7, name: "Eve Black", position: "Officer" },
    { id: 8, name: "Frank Green", position: "Coordinator" },
    { id: 9, name: "Grace Hill", position: "Officer" },
    { id: 10, name: "Hank Blue", position: "Assistant" },
  ];

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>
      <div className="officers-grid">
        {officers.map(officer => (
          <div className="officer-card" key={officer.id}>
            <h3>{officer.name}</h3>
            <p>{officer.position}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ManageOfficers;
